#include <bits/stdc++.h>
using namespace std;
int n;
set<unsigned long long> q;
int main(){
	string s;
	cin>>n;
	for(int i=1;i<=n;i++){
	    cin>>s;
	    unsigned long long a=0,b=1;
	    for(int i=0;i<s.size();i++)
	        a+=s[i]*s[i]*s[i]*s[i],b*=s[i];
	     q.insert(a+b);
	}
	cout<<q.size();
	return 0;
}
